	// DFCT0010827 - new function so completed on time, end date and empty start date are set consistently
	_setCompletedOnTime: function(task){
        var gdt = new GlideDateTime();
        // STRY0094943 - DFCT0010597
        if (!task.work_start)
            task.setValue('work_start', gdt.getValue());
		task.setValue('work_end', gdt.getValue());

        if (task.suspense_date != '') {
            if (task.suspense_date > gdt.getValue())
                task.u_completed_on_time = true;
            else
                task.u_completed_on_time = false;
        } else task.u_completed_on_time = true;
	},


    uiAction_UpdateTaskAndResponseLog: function(DecisionToClose, actionTaken, task) {
        var stateClosedFrom = task.state;
        task.decision = DecisionToClose;
        task.state = 3;
        task.active = 'false';
		// DFCT0010827 - called new function, this did not set start date when empty
		this._setCompletedOnTime(task);

        switch (actionTaken) {
			case 'abstain':
				// TODO - multilanguage
				task.work_notes = "Reviewer Decision: " + task.decision + " by " + task.assigned_to.getDisplayValue().toString();
				break;
            case 'reject':
                // STRY0097883 - DFCT0010460 
                task.work_notes = gs.getMessage("Tasker - Additional comments for the rejected Task Approval have been added by (Reviewer): {0}  (Comment): {1}",[gs.getUserDisplayName(), this.trimComments(task.comments_dt)]);
                break;
            case 'approve':
                task.work_notes = gs.getMessage('Tasker - This task has been approved by') + task.assigned_to.name;
                break;
            case 'concur':
                task.work_notes = gs.getMessage('Tasker - This task has been concurred by') + task.assigned_to.name;
                break;
            case 'nonconcur':
			case 'nonconcur_sign':
                // STRY0097883 - DFCT0010460 
                task.work_notes = gs.getMessage('Tasker - Additional comments for non-concurring of the Task have been added by (Reviewer): {0} (Comment): {1}', [gs.getUserDisplayName(), this.trimComments(task.comments_dt)]);
                break;
            case 'approve_sign':
            case 'concur_sign':
                task.work_notes = gs.getMessage('Tasker - This task has been signed by') + task.assigned_to.name;
                break;
        }

		// STRY0106180 - clear all request fields
		task.u_clarification_requested = false;
		task.extension_requested = false;
		task.reassignment_requested = false;
		task.extended_suspense_date = null;

        task.update();
		// DFCT0010577 - this was moved out of the business rule and performed here
		this._clearOpenRequestsForTask(task);
		var currentUser =  gs.getUserID();
        var isTaskeOwner = task.u_task_requester == currentUser;
        var isReviewer = task.u_reviewer == currentUser;
        var isAssignedMember = task.assigned_to == currentUser;

		// DFCT0010577 
		var role = '';
		if (stateClosedFrom == '14') {
            role = isReviewer ? 'reviewer' : isTaskeOwner ? 'task_owner' : '';
        } else {
            role = isAssignedMember ? 'assigned_member' : isTaskeOwner ? 'task_owner' : isReviewer ? 'reviewer' : '';
        }
		this._addResponseLog(task, role, currentUser, actionTaken, task.comments_dt);

        gs.addInfoMessage(task.number + gs.getMessage('Tasker - has been successfully') + DecisionToClose + gs.getMessage('Tasker - and marked as Completed'));

		// DFCT0010577 - this was moved out of the business rule and performed here
		this._closeRelatedTasks(task);
    },

    uiAction_MarkTaskCompleteAndUpdateResponseLog: function(task) {
        // may need to compare to the function above there is a lot of overlap
        var stateClosedFrom = task.getValue('state');
        var isTaskeOwner = task.u_task_requester == gs.getUserID();
        var isReviewer = task.u_reviewer == gs.getUserID();
        var isAssignedMember = task.assigned_to == gs.getUserID();

        task.decision = 'N/A';
        task.state = 3;
        task.active = 'false';

		// DFCT0010827 - called new function, for consistency
		this._setCompletedOnTime(task);

		// STRY0106180 - clear all request fields
		task.u_clarification_requested = false;
		task.extension_requested = false;
		task.reassignment_requested = false;
		task.extended_suspense_date = null;

        task.update();
		// DFCT0010577 - this was moved out of the business rule and performed here
		this._clearOpenRequestsForTask(task);

		// DFCT0010577 
		var role = '';
		var respondedBy = '';
		var actionTaken = '';
        if (stateClosedFrom == '14') {
            // making the entery for sent to review for the assigned member if state 14
            role = 'assigned_member';
            respondedBy = task.assigned_to;
            actionTaken = 'sent_to_review';
        } else {
            // making the entery for sent to review for the assigned member if state 14
            role = isAssignedMember ? 'assigned_member' : isTaskeOwner ? 'task_owner' : isReviewer ? 'reviewer' : '';
            respondedBy = gs.getUserID();
            actionTaken = 'completed';
        }
		this._addResponseLog(task, role, respondedBy, actionTaken, task.response);

        // now create the Reviewer entre IF the state is 14
        if (stateClosedFrom == '14') {
            role = isReviewer ? 'reviewer' : isTaskeOwner ? 'task_owner' : '';
            actionTaken = 'completed';
			this._addResponseLog(task, role, gs.getUserID(), actionTaken, task.comments_dt);
        }

        gs.addInfoMessage(task.number + gs.getMessage('Tasker - has been marked as Completed'));
		// DFCT0010577 - this was moved out of the business rule and performed here
		this._closeRelatedTasks(task);
    },

    uiAction_AssignTask: function(task) {
        var now = new GlideDateTime();
        var bDateOk = true;
        if (gs.getProperty('x_153465_discovert.Suspense Dates and Expected Start Dates must be in the future') == 'true') {
            if (now > task.suspense_date && task.suspense_date != "") {
                // DFCT0010681 - fixed multilanguage while addressing other issue
                gs.addErrorMessage(gs.getMessage('The suspense date must be in the future.'));
                bDateOk = false;
            }
        }

        if (bDateOk) {
            if (task.assigned_to.nil() || task.primary_assignee.nil()) {
                var assignee = task.primary_assignee.getDisplayValue();
                task.state = -5;
                // TODO - multilanguage
                task.work_notes = "Assigned to " + assignee;
                task.update();
            } else {
                var assigned_to = task.assigned_to.getDisplayValue();
                task.state = 1;
                // TODO - multilanguage
                task.work_notes = "Assigned to " + assigned_to;
                task.update();
            }
        }
    },

