    uiAction_RejectExtensionRequest: function(request) {
        // TODO - multilanguage
        var errorMessage = 'Request ' + request.number + ' did not meet the conditions to submit a Reject Extension';

        // TODO - multilanguage
        if (request.u_request_type == "Extension") {
            // STRY0104533
            var parentId = request.parent.toString();
            var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
            if (grTask.get(parentId)) {
                var allow = new uiConditionCheck().RespondExtension(grTask);
                if (allow) {
                    // STRY0097883
                    // TODO - multilanguage
                    var taskWorkNotes = 'Extension Request has been rejected by ' + gs.getUserDisplayName() +
                        ' with the following comments: ' + this.trimComments(request.u_response_comments) + '. Note: The suspense date has not been updated.';

                    grTask.latest_extension_request_date = request.u_requested_suspense_date;
                    grTask.extended_suspense_date = '';
                    // TODO - multilanguage
                    grTask.extension_approval = 'Rejected';
                    grTask.extension_requested = false;
                    grTask.work_notes = taskWorkNotes;
                    grTask.update();

                    var todaysDate = new GlideDateTime();
                    // TODO - multilanguage
                    request.u_status = 'Completed'; //'Approved';
                    // TODO - multilanguage
                    request.u_response = 'Rejected';
                    request.u_responded_by = gs.getUserID();
                    request.u_responded = todaysDate;
                    request.update();

					// DFCT0010919
					gs.eventQueue('x_153465_discovert.NotifyExtensionReject', grTask);

                    gs.addInfoMessage(taskWorkNotes);
                } else gs.addErrorMessage(errorMessage);
            }
        } else gs.addErrorMessage(errorMessage);
    },

