					// DFCT0010921
					gs.eventQueue('x_153465_discovert.NotifyReassignmentRej', grTask);

                    gs.addInfoMessage(taskWorkNotes);
                } else gs.addErrorMessage(errorMessage);
            }
        } else gs.addErrorMessage(errorMessage);
    },

    uiAction_RejectTaskForPrimaryAssignee: function(task) {
		// STRY0122187
		var previous_primaryAssignee = task.getDisplayValue("primary_assignee");
        if (task.comments.nil()) {
            gs.addErrorMessage(gs.getMessage('Comments are required when rejecting a Task'));
        } else {
            task.state = 11;
            task.work_notes = gs.getMessage('Tasker - Comments for the Primary Assignee Task Rejection has been added by') + gs.getUserDisplayName();
            task.primary_assignee = "";
            task.update();
			// DFCT0010924
			gs.eventQueue('x_153465_discovert.NotifyOUAssignmentRej', task, previous_primaryAssignee);


            gs.addInfoMessage(task.number + gs.getMessage('Tasker -  has been rejected'));
        }
    },

