    uiAction_SaveAsTemplate: function(task) {
        // start the process of creating a new process definition
        // TODO - multilanguage
        gs.eventQueue('x_153465_discovert.Save_as_Template', task, 'Save as Template', gs.getUserID());
        // TODO - multilanguage
        gs.addInfoMessage("'" + task.task_name + "'" + ' has been saved as a Template. You can find it under' + '<a href="?id=discovertasker_processtemplatelist&table=x_153465_discovert_discover_routing_template&filter=process_level%3Dglobal_process%5ENQprocess_level%3Dou_process%5ENQprocess_level%3Dmy_process%5Eprocess_ownerDYNAMIC90d1921e5f510100a9ad2572f2b477fe%5EEQ"> Personal Templates </a>');

        var templateName = task.short_description;
        var gr = new GlideAggregate('x_153465_discovert_discover_routing_template');
        gr.addQuery('template_name', templateName);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            // TODO - multilanguage
            gs.addInfoMessage("There is already a Template with that name.  Saving Template as a copy.");
        }
    },

    uiAction_SendEmail: function(taskerEmail) {
