        // TODO - multilanguage
        gs.addInfoMessage(task.number + ' has been Started');
    },

    // STRY0108329 - changed a function to make more specific to Task
    uiAction_SubmitTaskRequest: function(request) {
        var errorMessage = '';
        var taskWorkNotes = '';
        var grTask;
        var parentId;
        var allow;
        var todaysDate = new GlideDateTime();

        //----------------------------------------------------------------------------------------------------------
        // Request Clarification
        //----------------------------------------------------------------------------------------------------------
        if (request.u_request_type == "Clarification") {
            // TODO - multilanguage
            errorMessage = 'Request ' + request.number + ' did not meet the conditions to submit a Request Clarification. Please validate that you are either the Assigned Member OR Reviewer OR Primary Assignee Task Manager (OUTA) OR Task Administrator (GTA), and that you are not all three the Task Owner, Assigned Member and Reviewer';

            parentId = request.parent.toString();
            grTask = new GlideRecord("x_153465_discovert_route_task_instance");
            if (grTask.get(parentId)) {
                allow = new uiConditionCheck().RequestClarification(grTask);
                if (allow) {
                    // STRY0097883
                    // TODO - multilanguage
                    taskWorkNotes = 'Clarification Request has been created by ' + gs.getUserDisplayName() + ' with the following comments: ' + this.trimComments(request.u_request_comments);
                    grTask.u_clarification_requested = true;
                    grTask.work_notes = taskWorkNotes;
                    grTask.update();

                    request.u_requested_by = gs.getUserID();
                    request.u_requested = todaysDate;
                    request.update();

                    gs.addInfoMessage(taskWorkNotes);
                    //get the person who is going to receive
                    var recipient = grTask.getValue('u_task_requester').toString();
                    var requestedby = gs.getUserDisplayName(); //request.getValue('u_requested_by').toString();

                    // STRY0071902
                    // Task Owner, if active and assigned to is set
                    if (grTask.active && (grTask.u_task_requester + '' != '')) {
                        recipient = recipient + ',' + grTask.getValue('u_task_requester').toString();
                    }
                    // Assigned To, if active and assigned to is set
                    if (grTask.active && (grTask.assigned_to + '' != '')) {
                        recipient = recipient + ',' + grTask.getValue('assigned_to').toString();
                    }
                    if (grTask.active && (grTask.state == 14) && (grTask.u_reviewer + '' != '')) {
                        recipient = recipient + ',' + grTask.getValue('u_reviewer').toString();
                    }
                    // top Task, send request to Primary OU Task Managers
                    if (grTask.active && (grTask.parent + '' == '')) {
                        recipient = recipient + ',' + grTask.primary_office.tasking_authorities;
                    }
                    // subTask, send request to Primary OU Task Managers
                    if (grTask.active && (grTask.parent + '' != '') && (grTask.primary_assignee + '' != '') && (grTask.primary_assignee.tasking_authorities + '' != '')) {
                        recipient = recipient + ',' + grTask.primary_assignee.tasking_authorities;
                    }
                    // subTask, send request to Primary OU Task Managers
                    if (grTask.active && (grTask.parent + '' != '') && (grTask.primary_assignee + '' == '')) {
                        recipient = recipient + ',' + grTask.primary_office.u_global_authorities;
                    }

                    gs.eventQueue('x_153465_discovert.NotifClarificationReq', grTask, requestedby, recipient);
                    //-------
                } else gs.addErrorMessage(errorMessage);
            } else gs.addErrorMessage(errorMessage);
        }

        //----------------------------------------------------------------------------------------------------------
        // Request Extension
        //----------------------------------------------------------------------------------------------------------
        if (request.u_request_type == "Extension") {
            // TODO - multilanguage
            errorMessage = 'Request ' + request.number + ' did not meet the conditions to submit a Request Extension';
            // STRY0104349 
            parentId = request.parent.toString();
            grTask = new GlideRecord("x_153465_discovert_route_task_instance");
            if (grTask.get(parentId)) {
                allow = new uiConditionCheck().RequestExtension(grTask);
                if (allow) {
                    // STRY0097883
                    // TODO - multilanguage
                    taskWorkNotes = 'Extension Request has been created by ' + gs.getUserDisplayName() + ' (Assignee) with the requested suspense date: ' + request.u_requested_suspense_date + ' and the following comments: ' + this.trimComments(request.u_request_comments);
                    grTask.extended_suspense_date = request.u_requested_suspense_date;
                    grTask.extension_approval = '';
                    grTask.extension_requested = true;
                    grTask.work_notes = taskWorkNotes;
                    grTask.update();

                    request.u_requested_by = gs.getUserID();
                    request.u_requested = todaysDate;
                    request.update();
					// DFCT0010923
					gs.eventQueue('x_153465_discovert.NotifyExtensionReques', grTask);
                    gs.addInfoMessage(taskWorkNotes);
                } else gs.addErrorMessage(errorMessage);
            } else gs.addErrorMessage(errorMessage);
        }

        //----------------------------------------------------------------------------------------------------------
        // Request Reassignment
        //----------------------------------------------------------------------------------------------------------
        if (request.u_request_type == "Reassignment") {
            // TODO - multilanguage
            errorMessage = 'Request ' + request.number + ' did not meet the conditions to submit a Request Reassignment';

            parentId = request.parent.toString();
            grTask = new GlideRecord("x_153465_discovert_route_task_instance");
            if (grTask.get(parentId)) {
                allow = new uiConditionCheck().RequestReassignment(grTask);
                if (allow) {
                    // STRY0097883
                    // TODO - multilanguage
                    taskWorkNotes = 'Reassignment Request has been created by ' + gs.getUserDisplayName() + ' (Assignee) with the following comments: ' + this.trimComments(request.u_request_comments);
                    grTask.reassignment_approval = '';
                    grTask.reassignment_requested = 'true';
                    grTask.work_notes = taskWorkNotes;
                    grTask.update();

                    request.u_requested_by = gs.getUserID();
                    request.u_requested = todaysDate;
                    request.update();
                    gs.addInfoMessage(taskWorkNotes);
                } else gs.addErrorMessage(errorMessage);
            } else gs.addErrorMessage(errorMessage);
        }
    },

    uiAction_Update: function(task) {
        task.update();
    },

    type: 'Task_uiAction'
};
